import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Project, ProjectStatus } from '../../core/models';

/**
 * SiteView projects list (`/projects`). Renders project cards that link to the
 * project detail shell. The status filter is URL-addressable via the `status`
 * query param. Planner-only "New project" action is gated behind the role.
 *
 * DATA CONTRACT: `projects` is a signal<Project[]> of mock data; the
 * service_agent stage clears it and wires ApiService.listProjects() in ngOnInit.
 */
@Component({
  selector: 'app-projects-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './projects-list.component.html',
  styleUrl: './projects-list.component.css',
})
export class ProjectsListComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly projects = signal<Project[]>([
    { id: 'p1', name: 'Riverside Community Center', status: 'active', phaseCount: 3, taskCount: 8, progressPct: 46 },
    { id: 'p2', name: 'Harbor Point Residential Tower', status: 'active', phaseCount: 5, taskCount: 21, progressPct: 62 },
    { id: 'p3', name: 'Oakwood Elementary Retrofit', status: 'planning', phaseCount: 4, taskCount: 12, progressPct: 8 },
    { id: 'p4', name: 'Meridian Logistics Warehouse', status: 'on_hold', phaseCount: 3, taskCount: 9, progressPct: 34 },
    { id: 'p5', name: 'Cedar Falls Pedestrian Bridge', status: 'complete', phaseCount: 2, taskCount: 6, progressPct: 100 },
  ]);

  readonly filter = signal<ProjectStatus | 'all'>('all');

  readonly statuses: { key: ProjectStatus | 'all'; label: string }[] = [
    { key: 'all', label: 'All' },
    { key: 'planning', label: 'Planning' },
    { key: 'active', label: 'Active' },
    { key: 'on_hold', label: 'On hold' },
    { key: 'complete', label: 'Complete' },
  ];

  readonly visible = computed<Project[]>(() => {
    const f = this.filter();
    const all = this.projects();
    return f === 'all' ? all : all.filter((p) => p.status === f);
  });

  constructor(
    public auth: AuthService,
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    const s = this.route.snapshot.queryParamMap.get('status') as ProjectStatus | null;
    if (s) this.filter.set(s);
  }

  setFilter(status: ProjectStatus | 'all'): void {
    this.filter.set(status);
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { status: status === 'all' ? null : status },
      queryParamsHandling: 'merge',
    });
  }

  statusLabel(s: ProjectStatus): string {
    return { planning: 'Planning', active: 'Active', on_hold: 'On hold', complete: 'Complete' }[s];
  }
  statusClass(s: ProjectStatus): string {
    return {
      planning: 'badge-muted',
      active: 'badge-info',
      on_hold: 'badge-warn',
      complete: 'badge-ok',
    }[s];
  }
}
